sys_script_include.script:
var NFAPIHelper = Class.create();
NFAPIHelper.prototype = {
    initialize: function() {},

    /**
     * Processor may return newValues; otherwise use the flat map derived from nfData.
     */
    _resolveNewValues: function(normalizedOutput, nfData) {
        const fromProcessor = normalizedOutput.newValues;
        if (fromProcessor && typeof fromProcessor === 'object' && !Array.isArray(fromProcessor)) {
            return fromProcessor;
        }
        return nfData;
    },

    _serviceError: function(status, message, detail) {
        var err = new sn_ws_err.ServiceError();
        err.setStatus(status);
        err.setMessage(message);
        if (!gs.nil(detail)) {
            err.setDetail(String(detail));
        }
        throw err;
    },

    generate: function(nextFormId, input) {
        if (gs.nil(nextFormId)) {
            this._serviceError(400, 'nextform_id is required');
        }
        var nfGr = new GlideRecord('x_snc_nf_nextform');
        if (!nfGr.get(nextFormId)) {
            this._serviceError(404, 'NextForm record not found', nextFormId);
        }
        var generatorGr = nfGr.generator.getRefRecord();
        if (!generatorGr || !generatorGr.isValidRecord()) {
            this._serviceError(400, 'NextForm has no generator configured', nextFormId);
        }
        var evaluator = new GlideScopedEvaluator();
        if (!gs.nil(input)) {
            evaluator.putVariable('input', input);
        }
        var nf;
        try {
            nf = evaluator.evaluateScript(generatorGr, 'script');
        } catch (ex) {
            gs.error('NextForm generator script failed: ' + ex.message + '\n' + ex.stack);
            this._serviceError(500, 'Generator script failed', String(ex));
        }
        if (gs.nil(nf) || typeof nf.toJSON !== 'function') {
            this._serviceError(500, 'Generator script must return an object with a toJSON method');
        }
        try {
            return nf.toJSON();
        } catch (ex2) {
            gs.error('NextForm form serialization failed: ' + ex2);
            this._serviceError(500, 'Form serialization failed', String(ex2));
        }
    },

    process: function(nextFormId, nfData, metadata) {
        if (gs.nil(nextFormId)) {
            this._serviceError(400, 'nextform_id is required');
        }
        var nfGr = new GlideRecord('x_snc_nf_nextform');
        if (!nfGr.get(nextFormId)) {
            this._serviceError(404, 'NextForm record not found', nextFormId);
        }
        var processorGr = nfGr.processor.getRefRecord();
        if (!processorGr || !processorGr.isValidRecord()) {
            this._serviceError(400, 'NextForm has no processor configured', nextFormId);
        }
        var evaluator = new GlideScopedEvaluator();
        evaluator.putVariable('nfData', nfData);
        if (!gs.nil(metadata)) {
            evaluator.putVariable('metadata', metadata);
        }
        try {
            const output = evaluator.evaluateScript(processorGr, 'script');
            const normalizedOutput = typeof output === 'object' && output !== null ? output : {
                success: false,
                message: "No processor output"
            };
            let success = false;
            if (typeof normalizedOutput.success !== 'undefined') {
                success = normalizedOutput.success === true || normalizedOutput.success === 'true' || normalizedOutput.success === 1 || normalizedOutput.success === '1';
            }

            var message = normalizedOutput.message != null ? String(normalizedOutput.message) : '';
            var newValues = this._resolveNewValues(normalizedOutput, nfData);

            return {
                success: success,
                message: message,
                newValues: newValues ?? {}
            };
        } catch (ex) {
            gs.error('NextForm processor script failed: ' + ex);
            this._serviceError(500, 'Processor script failed', String(ex));
        }
    },

    type: 'NFAPIHelper'
};
